SELECT e.employee_id, e.employee_name, e.employee_tier, s.total_points, s.capability_index, CASE WHEN o.difficulty_grade IS NULL THEN 'EFFICIENCY_TYPE' WHEN CASE o.difficulty_grade WHEN 'D5' THEN 3 WHEN 'D4' THEN 2 WHEN 'D3' THEN 1 ELSE 0 END > CASE e.employee_tier WHEN 'S' THEN 3 WHEN 'A' THEN 2 WHEN 'B' THEN 1 ELSE 0 END THEN 'GROWTH_TYPE' ELSE 'EFFICIENCY_TYPE' END AS matching_mode FROM employee e LEFT JOIN score s ON e.employee_id = s.employee_id LEFT JOIN orders o ON o.order_id = #{orderId} WHERE e.employee_role = 'WORKER' AND e.employee_status = 'ACTIVE' AND e.employee_id IN
#{id}
ORDER BY s.total_points DESC
